import React from 'react';
import './App.css';
import WordCloud from './components/WordCloud';
import Navigation from './components/Navigation';

const fakeWords = {
  cloud: 15,
  scope: 12,
  gmail: 10,
  email: 8,
  text: 6,
  word: 5,
  data: 4,
  analysis: 3,
  personal: 2,
  thoughts: 1
};

function App() {
  const [loading, setLoading] = React.useState(true);
  const [authenticated, setAuthenticated] = React.useState(false);

  React.useEffect(() => {
    setTimeout(() => {
      setAuthenticated(true);
      setLoading(false);
    }, 1000);
  }, []);

  if (loading) {
    return (
      <div className="app">
        Loading... {authenticated ? 'auth=true' : 'auth=false'}
      </div>
    );
  }

  return (
    <div className="app">
      <Navigation authenticated={authenticated} setAuthenticated={setAuthenticated} />
      <WordCloud words={fakeWords} />
    </div>
  );
}

export default App;
